#!/usr/bin/env node
// skillsmith-install — fetch a shared skill by its short ID and write the
// SKILL.md to the right place. Single arg: 6–16 char alphanumeric ID
// generated by the Skillsmith web app's share endpoint.
//
// Path computation here MUST stay in sync with `buildArtifacts` in
// src/skill-formats.ts of the Skillsmith web app — the two surfaces share a
// record format but no code, so changes need to be mirrored on both sides.

import fs from "node:fs";
import path from "node:path";
import os from "node:os";

const DEFAULT_SERVER = "https://skillsmith.vercel.app";

const HELP = `skillsmith-install — install a Skillsmith-authored agent skill.

usage:
  npx -y skillsmith-install@latest <id> [--force] [--server=<url>]
  npx -y skillsmith-install@latest --help

  <id>          short ID copied from the Skillsmith install panel
  --force       overwrite an existing file at the install path
  --server=URL  fetch from a non-default Skillsmith deployment
                (default: ${DEFAULT_SERVER})
                also reads SKILLSMITH_SERVER env var
`;

function die(msg, code = 1) {
  process.stderr.write(`skillsmith-install: ${msg}\n`);
  process.exit(code);
}

function reloadHint(target) {
  if (target === "claude") return "Start a new chat — Claude picks up new skills automatically.";
  if (target === "cursor") return "Reload Cursor (Cmd+Shift+P → Reload Window) so the new rule registers.";
  return "Drop this wherever your agent reads instructions from.";
}

function installPath(target, scope, slug) {
  if (target === "claude" && scope === "global") {
    return path.join(os.homedir(), ".claude", "skills", slug, "SKILL.md");
  }
  if (target === "claude") {
    return path.join(process.cwd(), ".claude", "skills", slug, "SKILL.md");
  }
  if (target === "cursor") {
    return path.join(process.cwd(), ".cursor", "rules", `${slug}.mdc`);
  }
  return path.join(process.cwd(), `${slug}.md`);
}

const argv = process.argv.slice(2);
if (argv.length === 0) {
  process.stderr.write(HELP);
  process.exit(1);
}
if (argv[0] === "--help" || argv[0] === "-h") {
  process.stdout.write(HELP);
  process.exit(0);
}

const force = argv.includes("--force");
const serverFlag = argv.find(a => a.startsWith("--server="));
const server = (serverFlag ? serverFlag.slice("--server=".length) : null)
  || process.env.SKILLSMITH_SERVER
  || DEFAULT_SERVER;
const id = argv.find(a => !a.startsWith("--"));
if (!id) die("missing id — copy the npx command from Skillsmith");
if (!/^[a-z0-9]{6,16}$/.test(id)) {
  die(`invalid id: ${id} (expected 6-16 lowercase alphanumeric characters)`);
}

// Fetch the skill record from the share server.
let payload;
try {
  const url = `${server.replace(/\/$/, "")}/api/skill?id=${encodeURIComponent(id)}`;
  const res = await fetch(url);
  if (res.status === 404) die(`skill not found — the ID may have expired (90 day TTL) or never existed`);
  if (!res.ok) die(`server error (${res.status}) fetching ${url}`);
  const text = await res.text();
  payload = JSON.parse(text);
} catch (err) {
  if (err && err.message && err.message.startsWith("skillsmith-install:")) throw err;
  die(`couldn't reach skillsmith server (${server}): ${err && err.message ? err.message : err}`);
}

const { v, target, scope, slug, content } = payload || {};
if (v !== 1) {
  die(
    `unsupported payload version: ${v} (expected 1) — update with ` +
    `'npm install -g skillsmith-install@latest'`,
  );
}
if (!target || !slug || typeof content !== "string") {
  die("malformed skill record — re-copy the npx command from Skillsmith");
}
if (!["claude", "cursor", "generic"].includes(target)) {
  die(`unknown target: ${target}`);
}
if (target === "claude" && !["global", "project"].includes(scope)) {
  die(`unknown scope for claude target: ${scope}`);
}
if (!/^[a-z0-9-]+$/.test(slug)) {
  die(`invalid slug: ${slug} (lowercase letters, digits, hyphens only)`);
}

const filePath = installPath(target, scope, slug);
const dir = path.dirname(filePath);

if (fs.existsSync(filePath) && !force) {
  die(`file exists at ${filePath} — re-run with --force to overwrite`);
}

try {
  fs.mkdirSync(dir, { recursive: true });
  fs.writeFileSync(filePath, content, "utf-8");
} catch (err) {
  die(`couldn't write ${filePath}: ${err && err.message ? err.message : err}`);
}

process.stdout.write(`✶ installed ${slug} → ${filePath}\n`);
process.stdout.write(`  ${reloadHint(target)}\n`);
